CREATE TABLE IF NOT EXISTS valora.responses (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NOT NULL REFERENCES valora.organizations(id), survey_id uuid NOT NULL REFERENCES valora.surveys(id), form_id uuid NOT NULL REFERENCES valora.forms(id), participant_name text, participant_email text, participant_phone text, participant_document text, participant_type text, result_token_hash text UNIQUE, status text NOT NULL DEFAULT 'completed', completed_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), is_deleted boolean NOT NULL DEFAULT false);
CREATE TABLE IF NOT EXISTS valora.response_answers (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), response_id uuid NOT NULL REFERENCES valora.responses(id), question_id uuid NOT NULL REFERENCES valora.questions(id), answer_json jsonb NOT NULL DEFAULT '{}'::jsonb, answer_text text, score numeric(10,2), max_score numeric(10,2));
CREATE TABLE IF NOT EXISTS valora.result_scores (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), response_id uuid NOT NULL REFERENCES valora.responses(id), total_score numeric(10,2), max_score numeric(10,2), percentage numeric(10,2), maturity_level text, maturity_label text, strategic_truth text, devolutiva_json jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS valora.dimension_scores (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), response_id uuid NOT NULL REFERENCES valora.responses(id), dimension_name text NOT NULL, score numeric(10,2), max_score numeric(10,2), percentage numeric(10,2), level_label text);
CREATE TABLE IF NOT EXISTS valora.certificates (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), response_id uuid NOT NULL REFERENCES valora.responses(id), certificate_code text NOT NULL UNIQUE, participant_name text, issuer_name text, survey_name text, pdf_path text, png_path text, issued_at timestamptz NOT NULL DEFAULT now(), created_at timestamptz NOT NULL DEFAULT now());
